.darma-loader-darma-custom-691 {
  color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: var(--loader-secondary-color, #67e8f9);
  --loader-bg: var(--loader-bg, #ffffff);
width: 45px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(currentColor 0 0);
background:
var(--c) 0 0,
var(--c) 50% 50%,
var(--c) 100% 100%;
animation:
darma-loader-darma-custom-691-l17 1s infinite alternate;
}
